const input = $json;

const workflowId      = input?.workflow?.id ?? 'unknown_workflow_id';
const workflowName    = input?.workflow?.name ?? 'Unknown Workflow';
const executionId     = input?.execution?.id ?? input?.trigger?.id ?? 'unknown_execution_id';
const errorMessage    = input?.execution?.error?.message
                     ?? input?.trigger?.error?.message
                     ?? 'No error message captured';
const errorStack      = input?.execution?.error?.stack
                     ?? input?.trigger?.error?.stack
                     ?? '';
const failingNode     = input?.execution?.error?.node?.name
                     ?? input?.trigger?.error?.node?.name
                     ?? 'Unknown Node';
const failingNodeType = input?.execution?.error?.node?.type
                     ?? input?.trigger?.error?.node?.type
                     ?? 'Unknown Type';
const errorMode       = input?.execution?.error ? 'execution' : 'trigger';
const timestamp       = new Date().toISOString();

const baseUrl      = $env?.N8N_BASE_URL ?? 'https://your-n8n-instance.com';
const executionUrl = `${baseUrl}/workflow/${workflowId}/executions/${executionId}`;

const stackTruncated = errorStack.length > 4000;
const truncatedStack = stackTruncated ? errorStack.substring(0, 4000) : errorStack;
const rawPayloadSnippet = JSON.stringify(input).substring(0, 3000);

return [{
  json: {
    workflowId, workflowName, executionId, errorMessage,
    errorStack: truncatedStack, stackTruncated,
    failingNode, failingNodeType, errorMode, timestamp,
    executionUrl, rawPayloadSnippet
  }
}];

const crypto = require('crypto');
const normalized = $('Normalize Error Data').first().json;
const claudeResponse = $json?.text ?? $json?.output ?? '';

let classification;
let classificationSource = 'claude';

try {
  if (!claudeResponse) throw new Error('Empty response from Claude');
  const clean = claudeResponse.replace(/```json/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(clean);
  if (!parsed.category || !parsed.severity || !parsed.summary) {
    throw new Error('Missing required fields in Claude response');
  }
  classification = parsed;
} catch (e) {
  classificationSource = 'fallback';
  classification = {
    category: 'UNKNOWN',
    severity: 'HIGH',
    summary: `LLM classification unavailable: ${e.message.substring(0, 80)}`,
    root_cause: `Claude failed to classify this error. Raw response: ${claudeResponse.substring(0, 400)}`,
    recommended_action: 'Review the raw error in the n8n execution log. LLM classification failed — check Anthropic API status.',
    is_transient: false
  };
}

const hashInput = `${normalized.workflowId}::${classification.category}`;
const dedupHash = crypto.createHash('sha256').update(hashInput).digest('hex').substring(0, 16);

const severityEmoji = { CRITICAL: '🔴', HIGH: '🟠', MEDIUM: '🟡', LOW: '🟢' };
const emoji = severityEmoji[classification.severity] ?? '⚪';
const jiraTitle = `${emoji} [n8n] ${classification.category} — ${normalized.workflowName}: ${classification.summary}`.substring(0, 255);

return [{
  json: {
    ...normalized,
    classification,
    classificationSource,
    dedupHash,
    jiraTitle,
    claudeRaw: claudeResponse
  }
}];

// ============================================================
// Route — Duplicate Check
// Single source of truth. Carries full context forward to both
// IF branches. existingIssueKey and existingIssueId are both
// stored so the comment node can use whichever the Jira node
// version requires.
// ============================================================

const allItems = $input.all();
const existingIssue = allItems[0]?.json ?? null;
const ctx = $('Parse & Hash Classification').first().json;

return [{
  json: {
    ...ctx,
    isDuplicate: allItems.length > 0,
    existingIssueKey: existingIssue?.key ?? null,
    existingIssueId:  existingIssue?.id  ?? null,
    existingIssueStatus: existingIssue?.fields?.status?.name ?? null
  }
}];

