const item = $json;

// jiraKey and action are always present — stamped by Set nodes upstream
const jiraKey = item.jiraKey ?? 'UNKNOWN';
const action  = item.action  ?? 'Unknown action';

const jiraBase = $env?.JIRA_BASE_URL ?? 'https://your-domain.atlassian.net/browse';
const jiraUrl  = `${jiraBase}/${jiraKey}`;

const severityColor = { CRITICAL: '#FF0000', HIGH: '#FF6600', MEDIUM: '#FFAA00', LOW: '#36A64F' };
const severityEmoji = { CRITICAL: ':red_circle:', HIGH: ':large_orange_circle:', MEDIUM: ':large_yellow_circle:', LOW: ':large_green_circle:' };
const color = severityColor[item.classification.severity] ?? '#808080';
const emoji = severityEmoji[item.classification.severity] ?? ':white_circle:';

const fallbackTag = item.classificationSource === 'fallback' ? ' [FALLBACK]' : '';
const fallbackNote = item.classificationSource === 'fallback' ? ' _(fallback — LLM unavailable)_' : '';

const slackPayload = {
  text: `${emoji} *n8n Error:* ${item.workflowName} — ${item.classification.category}`,
  attachments: [
    {
      color,
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: `${emoji} ${item.classification.severity} | ${item.classification.category}${fallbackTag}`, emoji: true }
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*${item.classification.summary}*${fallbackNote}` }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: `*Workflow:*\n<${item.executionUrl}|${item.workflowName}>` },
            { type: 'mrkdwn', text: `*Failing Node:*\n${item.failingNode}` },
            { type: 'mrkdwn', text: `*Error Mode:*\n${item.errorMode}` },
            { type: 'mrkdwn', text: `*Transient:*\n${item.classification.is_transient ? 'Yes' : 'No — manual fix required'}` }
          ]
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*Root Cause:*\n${item.classification.root_cause}` }
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*Recommended Action:*\n${item.classification.recommended_action}` }
        },
        {
          type: 'context',
          elements: [
            { type: 'mrkdwn', text: `Dedup Hash: \`${item.dedupHash}\` | ${action}: <${jiraUrl}|${jiraKey}> | ${item.timestamp}` }
          ]
        },
        {
          type: 'actions',
          elements: [
            { type: 'button', text: { type: 'plain_text', text: 'View Execution' }, url: item.executionUrl, style: 'primary' },
            { type: 'button', text: { type: 'plain_text', text: `Jira ${jiraKey}` }, url: jiraUrl }
          ]
        }
      ]
    }
  ]
};

return [{ json: { slackPayload, jiraKey, jiraUrl } }];
